import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() to read the entire line

        int bufferSize = 10; // Define buffer size
        char[] buffer = new char[bufferSize];

        // Copy user input into buffer with proper bounds checking
        for (int i = 0; i < Math.min(name.length(), bufferSize); i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
